class HttpRequestDirector {
    public void buildGetRequest(HttpRequest.Builder builder) {
        builder
            .timeout(30)
            .header("Accept", "application/json");
    }

    public void buildAuthenticatedPost(HttpRequest.Builder builder,
                                        String token, String body) {
        builder
            .body(body)
            .timeout(60)
            .header("Content-Type", "application/json")
            .header("Authorization", "Bearer " + token);
    }
}

// Client
HttpRequestDirector director = new HttpRequestDirector();

HttpRequest.Builder getBuilder = new HttpRequest.Builder("https://api.example.com/users", "GET");
director.buildGetRequest(getBuilder);
HttpRequest getReq = getBuilder.build();

HttpRequest.Builder postBuilder = new HttpRequest.Builder("https://api.example.com/users", "POST");
director.buildAuthenticatedPost(postBuilder, "token123", "{\"name\": \"Alice\"}");
HttpRequest postReq = postBuilder.build();
